async (page) => {
  const equipState = await page.evaluate(() => {
    const p = window.game.player;
    if (!p) return 'no player';
    return JSON.stringify({
      weaponKey: p.weaponKey || p.weapon,
      equipment: p.equipment ? Object.keys(p.equipment) : 'no equipment',
      weaponSlot: p.weaponSlot,
      armourKey: p.armourKey
    });
  });
  return equipState;
}

