async (page) => {
  // Update __talkToNPC to use correct packet 14
  await page.evaluate(() => {
    window.__talkToNPC = function(instanceId) {
      const game = window.game;
      if (!game || !game.socket) return { error: 'Game not loaded' };
      // Correct packet: [14, [0, instanceId]]
      game.socket.connection.send(JSON.stringify([14, [0, instanceId]]));
      const entity = game.entities?.get(instanceId);
      return { sent: true, npc: entity ? entity.name : instanceId, instance: instanceId };
    };
  });

  // Get nearby Oak trees
  const state = await page.evaluate(() => {
    const gs = window.__latestGameState;
    const trees = gs.nearby_entities ? gs.nearby_entities.filter(e => e.name === 'Oak' || e.name === 'Spruce') : [];
    return JSON.stringify({ pos: gs.player_position, trees: trees.slice(0, 5) });
  });
  return state;
}

