async (page) => {
  const click = (x, y) => page.evaluate(({x, y}) => {
    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true, ctrlKey: false }));
  }, {x, y});

  // Walk to Forester
  await click(696, 240);
  await page.waitForTimeout(2500);

  // Check distance
  const dist = await page.evaluate(() => {
    const gs = window.__latestGameState;
    const f = gs.nearby_entities ? gs.nearby_entities.find(e=>e.name==='Forester') : null;
    return f ? f.distance : 999;
  });

  if (dist > 1) {
    await click(696, 240);
    await page.waitForTimeout(2000);
  }

  // Now talk using correct packet
  await page.evaluate(() => {
    window.game.socket.connection.send(JSON.stringify([14, [0, '1-85756128']]));
  });
  await page.waitForTimeout(1500);
  await page.evaluate(() => {
    window.game.socket.connection.send(JSON.stringify([14, [0, '1-85756128']]));
  });
  await page.waitForTimeout(1500);
  await page.evaluate(() => {
    window.game.socket.connection.send(JSON.stringify([14, [0, '1-85756128']]));
  });
  await page.waitForTimeout(2000);

  await page.screenshot({ path: '/tmp/kaetram_agent_3/state/screenshot.png', type: 'png' });

  const state = await page.evaluate(() => {
    const gs = window.__latestGameState;
    const foresting = gs.quests ? gs.quests.find(q=>q.key==='foresting') : null;
    const logs = gs.inventory ? gs.inventory.filter(i=>i.key==='logs').reduce((s,i)=>s+i.count,0) : 0;
    const questDisplay = window.getComputedStyle(document.getElementById('quest')).display;
    return JSON.stringify({ pos: gs.player_position, foresting, logs, questDisplay });
  });
  return state;
}

async (page) => {
  const click = (x, y) => page.evaluate(({x, y}) => {
    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true, ctrlKey: false }));
  }, {x, y});

  // Keep clicking Forester until adjacent
  for (let i = 0; i < 5; i++) {
    const foresterInfo = await page.evaluate(() => {
      const gs = window.__latestGameState;
      const f = gs.nearby_entities ? gs.nearby_entities.find(e=>e.name==='Forester') : null;
      return f ? {dist: f.distance, cx: f.click_x, cy: f.click_y} : null;
    });

    if (!foresterInfo || foresterInfo.dist <= 1) break;

    if (foresterInfo.cx) {
      await click(foresterInfo.cx, foresterInfo.cy);
    } else {
      await click(640, 300);
    }
    await page.waitForTimeout(2500);
  }

  const dist = await page.evaluate(() => {
    const gs = window.__latestGameState;
    const f = gs.nearby_entities ? gs.nearby_entities.find(e=>e.name==='Forester') : null;
    return f ? {dist: f.distance, pos: gs.player_position} : null;
  });
  return dist;
}

