async (page) => {
  // Check skills via game internals
  const skills = await page.evaluate(() => {
    try {
      const player = window.game.player;
      const skillNames = ['Strength', 'Defense', 'Accuracy', 'Health', 'Lumberjacking'];
      const result = {};
      for (const name of skillNames) {
        const skill = player.skills[name.toLowerCase()] || player.skills[name];
        if (skill) result[name] = { level: skill.level, experience: skill.experience };
      }
      // Also try skills object directly
      if (player.skills) {
        result['_keys'] = Object.keys(player.skills);
      }
      return result;
    } catch(e) {
      return { error: e.message };
    }
  });
  return JSON.stringify(skills);
}

