  const npcs = await page.evaluate(() =>
    (window.__latestGameState.nearby_entities || [])
      .filter(e => e.type === 1 && e.distance < 40)
      .map(e => ({name: e.name, x: e.x, y: e.y, dist: e.distance, on_screen: e.on_screen}))
  );
  console.log('NPCs:', JSON.stringify(npcs));

  await page.screenshot({ path: '/tmp/kaetram_agent_3/state/screenshot.png', type: 'png' });
  return { pos, npcs };
}

async (page) => {
  const click = (x, y) => page.evaluate(({x, y}) => {
    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true, ctrlKey: false }));
  }, {x, y});

  // Navigate northeast toward Guard at (231, 145) - click guard directly as target
  // Guard is off-screen, need to navigate there
  // From (204, 153): 27 east, 8 north = screen (640+27*48, 360-8*48) = (1936, 24) - way off screen
  // Just click northeast direction repeatedly

  for (let i = 0; i < 10; i++) {
    await click(1100, 250);  // NE
    await page.waitForTimeout(2500);
    const pos = await page.evaluate(() => window.__latestGameState.player_position);
    const guard = await page.evaluate(() => {
      const s = window.__latestGameState;
      const g = (s.nearby_entities || []).find(e => e.name === 'Guard');
      return g ? {x: g.x, y: g.y, dist: g.distance, on_screen: g.on_screen, click_x: g.click_x, click_y: g.click_y} : null;
    });
    console.log(`Step ${i}: ${JSON.stringify(pos)}, guard=${JSON.stringify(guard)}`);
    if (guard && guard.on_screen) {
      await click(guard.click_x, guard.click_y);
      await page.waitForTimeout(3000);
      break;
    }
    if (pos.x >= 225) break;
  }

  await page.screenshot({ path: '/tmp/kaetram_agent_3/state/screenshot.png', type: 'png' });
  return await page.evaluate(() => window.__latestGameState.player_position);
}

